 * dp[i][j] would normally store the minimum XOR sum to reach (i, j).
 * However, XOR is not additive like standard path sums, so min(dp[i-1][j] ^ grid[i][j], dp[i][j-1] ^ grid[i][j]) 
 * might not yield the true minimum, because the previous XOR sums are different.
 *
 * Since grid[i][j] <= 1023, the maximum possible XOR sum is less than 2048 (11 bits).
 * We can use DP where the state includes the accumulated XOR sum.
 * 
 * Let dp[i][j] be a Set of all possible XOR sums to reach cell (i, j).
 * Since m*n <= 1000, the path length L <= 1000. The number of possible XOR sums is at most 2048.
 * The size of the state space would be M * N * 2048, which is around 1000 * 2048, feasible.
 */

fun solve(grid: Array<Array<Long>>): Long {
    val m = grid.size
    val n = grid[0].size

    // dp[i][j] stores the set of all possible XOR sums to reach cell (i, j).
    // Since grid elements are small (<= 1023), the XOR sum is < 2048.
    // We use BooleanArray for optimization if we map XOR sums to indices, 
    // but a Set<Int> is conceptually clearer for DP state transition here.
    val dp = Array(m) { Array<MutableSet<Int>>(n) { mutableSetOf() } }

    // Base case: (0, 0)
    dp[0][0].add(grid[0][0].toInt())

    // Fill the first row
    for (j in 1 until n) {
        // Only one way to reach (0, j): from (0, j-1)
        val currentVal = grid[0][j].toInt()
        for (xorSum in dp[0][j - 1]) {
            dp[0][j].add(xorSum xor currentVal)
        }
    }

    // Fill the first column
    for (i in 1 until m) {
        // Only one way to reach (i, 0): from (i-1, 0)
        val currentVal = grid[i][0].toInt()
        for (xorSum in dp[i - 1][0]) {
            dp[i][0].add(xorSum xor currentVal)
        }
    }

    // Fill the rest of the DP table
    for (i in 1 until m) {
        for (j in 1 until n) {
            val currentVal = grid[i][j].toInt()

            // From above (i-1, j)
            for (xorSum in dp[i - 1][j]) {
                dp[i][j].add(xorSum xor currentVal)
            }

            // From left (i, j-1)
            for (xorSum in dp[i][j - 1]) {
                dp[i][j].add(xorSum xor currentVal)
            }
        }
    }

    // The result is the minimum value in the set at the bottom-right corner
    val resultSet = dp[m - 1][n - 1]
    if (resultSet.isEmpty()) {
        // Should not happen given constraints
        return -1L 
    }

    return resultSet.minOrNull()!!.toLong()
}
